package com.example.myapplication
import android.os.Bundle import androidx.activity.enableEdgeToEdge import androidx.appcompat.app.AppCompatActivity import androidx.core.view.ViewCompat import androidx.core.view.WindowInsetsCompat
class MainActivity : AppCompatActivity() { override fun onCreate(savedInstanceState: Bundle?) { super.onCreate(savedInstanceState) enableEdgeToEdge() setContentView(R.layout.activity_main) ViewCompat.setOnApplyWindowInsetsListener(findViewById(R.id.main)) { v, insets -> val systemBars = insets.getInsets(WindowInsetsCompat.Type.systemBars()) v.setPadding(systemBars.left, systemBars.top, systemBars.right, systemBars.bottom) insets } } }

package com.example.redyseguridad

import android.os.Bundle
import androidx.appcompat.app.AppCompatActivity
import androidx.navigation.fragment.NavHostFragment
import androidx.navigation.ui.setupWithNavController
import com.example.redyseguridad.databinding.ActivityMainBinding

/**
 * Activity principal que actúa como contenedor de los fragments.
 * Integra Navigation Component con BottomNavigationView para navegar entre pantallas.
 * Utiliza ViewBinding para acceso seguro a los elementos de la UI.
 */
class MainActivity : AppCompatActivity() {

    // ViewBinding para acceso seguro a elementos de activity_main.xml
    private lateinit var binding: ActivityMainBinding

    override fun onCreate(savedInstanceState: Bundle?) {
        super.onCreate(savedInstanceState)

        // Inicializar ViewBinding en lugar de setContentView()
        binding = ActivityMainBinding.inflate(layoutInflater)
        setContentView(binding.root)

        // Configurar Navigation Component con BottomNavigationView
        setupNavigation()
    }

    /**
     * Configura la integración entre Navigation Component y BottomNavigationView.
     * Esto permite que los items del menú navegen automáticamente a los fragments correspondientes.
     */
    private fun setupNavigation() {
        // Obtener el NavHostFragment que contiene los fragments
        val navHostFragment = supportFragmentManager.findFragmentById(R.id.nav_host_fragment)
                as NavHostFragment

        // Obtener el NavController del NavHostFragment
        val navController = navHostFragment.navController

        // Conectar el BottomNavigationView con el NavController
        // Esto vincula los items del menú con los IDs de los fragmentos en el nav_graph
        binding.bottomNavigation.setupWithNavController(navController)
    }
}

package com.example.redyseguridad.network

import com.example.redyseguridad.model.Post
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import org.json.JSONObject
import java.io.BufferedReader
import java.io.InputStreamReader
import java.net.HttpURLConnection
import java.net.URL

/**
 * Singleton para manejar las comunicaciones HTTP de forma nativa.
 * Usa solo HttpURLConnection sin librerías de terceros (sin Retrofit, OkHttp, Volley, etc).
 * Todos los métodos son suspend functions que corren en Dispatchers.IO
 */
object HttpClient {

    private const val BASE_URL = "https://jsonplaceholder.typicode.com"
    private const val CONNECT_TIMEOUT = 10000  // 10 segundos
    private const val READ_TIMEOUT = 10000     // 10 segundos

    /**
     * Obtiene un post específico desde JSONPlaceholder.
     * Abre una conexión GET a /posts/{id}, lee la respuesta JSON y la parsea manualmente.
     *
     * @param id El ID del post a obtener
     * @return Data class Post con los datos parseados
     * @throws Exception si el servidor devuelve un código distinto a 200
     */
    suspend fun getPost(id: Int): Post = withContext(Dispatchers.IO) {
        val urlString = "$BASE_URL/posts/$id"
        val url = URL(urlString)

        // Abrir conexión HTTP
        val connection = url.openConnection() as HttpURLConnection
        connection.requestMethod = "GET"
        connection.connectTimeout = CONNECT_TIMEOUT
        connection.readTimeout = READ_TIMEOUT

        try {
            val responseCode = connection.responseCode

            // Verificar que la respuesta sea exitosa (200 OK)
            if (responseCode != HttpURLConnection.HTTP_OK) {
                throw Exception("Error HTTP $responseCode del servidor")
            }

            // Leer la respuesta del servidor con BufferedReader
            val inputStream = connection.inputStream
            val reader = BufferedReader(InputStreamReader(inputStream))
            val responseBody = reader.use { it.readText() }
            reader.close()

            // Parsear manualmente la respuesta JSON sin usar Gson ni Moshi
            val jsonObject = JSONObject(responseBody)
            val post = Post(
                id = jsonObject.getInt("id"),
                userId = jsonObject.getInt("userId"),
                title = jsonObject.getString("title"),
                body = jsonObject.getString("body")
            )
            post
        } finally {
            connection.disconnect()
        }
    }

    /**
     * Actualiza un post existente mediante una solicitud PUT.
     * Construye manualmente el JSON de envío, lo serializa y lo escribe en el OutputStream.
     *
     * @param id El ID del post a actualizar
     * @param title El nuevo título del post
     * @param body El nuevo cuerpo del post
     * @return El código de respuesta HTTP (usualmente 200 para éxito)
     */
    suspend fun putPost(id: Int, title: String, body: String): Int =
        withContext(Dispatchers.IO) {
            val urlString = "$BASE_URL/posts/$id"
            val url = URL(urlString)

            // Abrir conexión HTTP para PUT
            val connection = url.openConnection() as HttpURLConnection
            connection.requestMethod = "PUT"
            connection.connectTimeout = CONNECT_TIMEOUT
            connection.readTimeout = READ_TIMEOUT

            // Configurar headers para indicar que enviaremos JSON
            connection.setRequestProperty("Content-Type", "application/json; charset=utf-8")
            connection.doOutput = true

            try {
                // Construir manualmente el JSON de envío sin librerías
                val jsonBody = """{"id":$id,"title":"$title","body":"$body","userId":1}"""

                // Escribir el JSON en el OutputStream de la conexión
                val outputStream = connection.outputStream
                outputStream.write(jsonBody.toByteArray(Charsets.UTF_8))
                outputStream.flush()
                outputStream.close()

                // Obtener y retornar el código de respuesta
                connection.responseCode
            } finally {
                connection.disconnect()
            }
        }
}

package com.example.redyseguridad.ui.rest

import android.os.Bundle
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import androidx.fragment.app.Fragment
import androidx.fragment.app.viewModels
import androidx.lifecycle.Lifecycle
import androidx.lifecycle.lifecycleScope
import androidx.lifecycle.repeatOnLifecycle
import com.example.redyseguridad.databinding.FragmentRestBinding
import com.google.android.material.snackbar.Snackbar
import kotlinx.coroutines.launch

/**
 * Fragment que muestra la pantalla de conectividad REST.
 * Permite obtener un post desde JSONPlaceholder y actualizarlo.
 * Usa ViewBinding y recolecta el StateFlow del ViewModel de forma reactiva.
 */
class RestFragment : Fragment() {

    // ViewBinding para acceder a los elementos de la UI
    private lateinit var binding: FragmentRestBinding

    // ViewModel específico de este fragment
    private val viewModel: RestViewModel by viewModels()

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View? {
        // Inicializar binding
        binding = FragmentRestBinding.inflate(inflater, container, false)
        return binding.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        setupListeners()
        observeStateFlow()
    }

    /**
     * Configura los listeners de botones.
     */
    private fun setupListeners() {
        // Botón Consultar: obtiene el ID y llama a fetchPost
        binding.btnFetch.setOnClickListener {
            val idStr = binding.etPostId.text?.toString()?.trim()

            // Validar que el ID no esté vacío
            if (idStr.isNullOrEmpty()) {
                showErrorSnackbar("Por favor ingresa un ID válido")
                return@setOnClickListener
            }

            try {
                val id = idStr.toInt()
                // Llamar al ViewModel para obtener el post
                viewModel.fetchPost(id)
            } catch (e: NumberFormatException) {
                showErrorSnackbar("El ID debe ser un número")
            }
        }

        // Botón Actualizar: actualiza el post con los nuevos datos
        binding.btnUpdate.setOnClickListener {
            val idStr = binding.etPostId.text?.toString()?.trim()
            val title = binding.etTitle.text?.toString()?.trim()
            val body = binding.etBody.text?.toString()?.trim()

            // Validar que los campos no estén vacíos
            if (idStr.isNullOrEmpty() || title.isNullOrEmpty() || body.isNullOrEmpty()) {
                showErrorSnackbar("Todos los campos son requeridos")
                return@setOnClickListener
            }

            try {
                val id = idStr.toInt()
                // Llamar al ViewModel para actualizar el post
                viewModel.updatePost(id, title, body)
            } catch (e: NumberFormatException) {
                showErrorSnackbar("El ID debe ser un número")
            }
        }
    }

    /**
     * Recolecta el StateFlow del ViewModel y responde a los cambios de estado.
     * Usa lifecycleScope.launch con repeatOnLifecycle para evitar memory leaks.
     */
    private fun observeStateFlow() {
        viewLifecycleOwner.lifecycleScope.launch {
            // Recopilar el StateFlow solo cuando el fragment está en estado STARTED
            viewLifecycleOwner.repeatOnLifecycle(Lifecycle.State.STARTED) {
                viewModel.uiState.collect { state ->
                    when (state) {
                        // Estado Idle: UI limpia, sin datos
                        is UiState.Idle -> {
                            clearUI()
                            enableAllUI()
                        }

                        // Estado Loading: mostrar indicador de progreso, deshabilitar UI
                        is UiState.Loading -> {
                            disableAllUI()
                            binding.progressBar.visibility = View.VISIBLE
                        }

                        // Estado Success: llenar los campos con los datos obtenidos
                        is UiState.Success -> {
                            enableAllUI()
                            binding.progressBar.visibility = View.GONE
                            binding.etTitle.setText(state.post.title)
                            binding.etTitle.isEnabled = true
                            binding.etBody.setText(state.post.body)
                            binding.etBody.isEnabled = true
                            binding.btnUpdate.isEnabled = true
                        }

                        // Estado Updated: mostrar mensaje de éxito
                        is UiState.Updated -> {
                            enableAllUI()
                            binding.progressBar.visibility = View.GONE
                            showSuccessSnackbar("✓ Post actualizado correctamente")
                            // Opcionalmente, resetear el estado después de un tiempo
                            viewModel.resetState()
                        }

                        // Estado Error: mostrar mensaje de error
                        is UiState.Error -> {
                            enableAllUI()
                            binding.progressBar.visibility = View.GONE
                            showErrorSnackbar("Error: ${state.message}")
                        }
                    }
                }
            }
        }
    }

    /**
     * Limpia todos los campos de entrada.
     */
    private fun clearUI() {
        binding.etPostId.text?.clear()
        binding.etTitle.text?.clear()
        binding.etBody.text?.clear()
        binding.btnUpdate.isEnabled = false
        binding.etTitle.isEnabled = false
        binding.etBody.isEnabled = false
    }

    /**
     * Habilita todos los controles de la UI.
     */
    private fun enableAllUI() {
        binding.etPostId.isEnabled = true
        binding.btnFetch.isEnabled = true
    }

    /**
     * Deshabilita todos los controles de la UI (durante una carga).
     */
    private fun disableAllUI() {
        binding.etPostId.isEnabled = false
        binding.btnFetch.isEnabled = false
        binding.btnUpdate.isEnabled = false
    }

    /**
     * Muestra un Snackbar con un mensaje de éxito.
     */
    private fun showSuccessSnackbar(message: String) {
        Snackbar.make(binding.root, message, Snackbar.LENGTH_SHORT).show()
    }

    /**
     * Muestra un Snackbar con un mensaje de error.
     */
    private fun showErrorSnackbar(message: String) {
        Snackbar.make(binding.root, message, Snackbar.LENGTH_LONG).show()
    }
}

package com.example.redyseguridad.ui.rest

import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import com.example.redyseguridad.model.Post
import com.example.redyseguridad.network.HttpClient
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.launch

/**
 * Sealed class que representa los diferentes estados de la UI para la pantalla REST.
 * Esto es parte del patrón MVVM con StateFlow para reactividad.
 */
sealed class UiState {
    /** Estado inicial: sin datos ni operación en curso */
    data object Idle : UiState()

    /** Estado mientras se realiza una operación HTTP */
    data object Loading : UiState()

    /** Estado tras obtener un post exitosamente */
    data class Success(val post: Post) : UiState()

    /** Estado tras actualizar un post exitosamente */
    data object Updated : UiState()

    /** Estado cuando ocurre un error */
    data class Error(val message: String) : UiState()
}

/**
 * ViewModel para la pantalla REST.
 * Maneja la lógica de obtener y actualizar posts desde JSONPlaceholder.
 * Usa Coroutines con viewModelScope y Dispatchers.IO para operaciones de red.
 */
class RestViewModel : ViewModel() {

    // StateFlow expuesto a la UI para que se actualice reactivamente
    private val _uiState = MutableStateFlow<UiState>(UiState.Idle)
    val uiState: StateFlow<UiState> = _uiState

    /**
     * Obtiene un post por su ID desde JSONPlaceholder.
     * Emite Loading → Success/Error dependiendo del resultado.
     *
     * @param id El ID del post a obtener
     */
    fun fetchPost(id: Int) {
        // Validar que el ID sea válido
        if (id <= 0) {
            _uiState.value = UiState.Error("El ID debe ser mayor a 0")
            return
        }

        // Lanzar coroutine en viewModelScope para que se cancele si el ViewModel es destruido
        viewModelScope.launch {
            // Emitir estado Loading
            _uiState.value = UiState.Loading

            try {
                // Llamar a HttpClient.getPost que corre en Dispatchers.IO
                val post = HttpClient.getPost(id)

                // Emitir estado Success con el post obtenido
                _uiState.value = UiState.Success(post)
            } catch (e: Exception) {
                // En caso de error, emitir el mensaje de error
                val errorMessage = e.message ?: "Error desconocido al obtener el post"
                _uiState.value = UiState.Error(errorMessage)
            }
        }
    }

    /**
     * Actualiza un post existente mediante una solicitud PUT.
     * Emite Loading → Updated/Error dependiendo del resultado.
     *
     * @param id El ID del post a actualizar
     * @param title El nuevo título
     * @param body El nuevo cuerpo del post
     */
    fun updatePost(id: Int, title: String, body: String) {
        // Validar que los campos no estén vacíos
        if (title.isBlank() || body.isBlank()) {
            _uiState.value = UiState.Error("Título y cuerpo no pueden estar vacíos")
            return
        }

        // Lanzar coroutine en viewModelScope
        viewModelScope.launch {
            // Emitir estado Loading
            _uiState.value = UiState.Loading

            try {
                // Llamar a HttpClient.putPost que corre en Dispatchers.IO
                val responseCode = HttpClient.putPost(id, title, body)

                // Verificar que la solicitud fue exitosa (HTTP 200)
                if (responseCode == 200) {
                    _uiState.value = UiState.Updated
                } else {
                    _uiState.value = UiState.Error("Error: código HTTP $responseCode")
                }
            } catch (e: Exception) {
                // En caso de error, emitir el mensaje de error
                val errorMessage = e.message ?: "Error desconocido al actualizar el post"
                _uiState.value = UiState.Error(errorMessage)
            }
        }
    }

    /**
     * Reinicia el estado a Idle. Útil cuando se descarta o resetea la pantalla.
     */
    fun resetState() {
        _uiState.value = UiState.Idle
    }
}

package com.example.redyseguridad.ui.storage

import android.os.Bundle
import android.view.LayoutInflater
import android.view.View
import android.view.ViewGroup
import androidx.fragment.app.Fragment
import androidx.fragment.app.viewModels
import androidx.lifecycle.Lifecycle
import androidx.lifecycle.lifecycleScope
import androidx.lifecycle.repeatOnLifecycle
import com.example.redyseguridad.databinding.FragmentStorageBinding
import com.google.android.material.snackbar.Snackbar
import kotlinx.coroutines.launch

/**
 * Fragment que muestra la pantalla de Almacenamiento Seguro.
 * Permite guardar y recuperar valores usando tres tipos de almacenamiento:
 * - SharedPreferences
 * - Jetpack DataStore
 * - EncryptedSharedPreferences
 *
 * Usa ViewBinding y recolecta el StateFlow del ViewModel de forma reactiva.
 */
class StorageFragment : Fragment() {

    // ViewBinding para acceder a los elementos de la UI
    private lateinit var binding: FragmentStorageBinding

    // ViewModel específico de este fragment
    private val viewModel: StorageViewModel by viewModels()

    override fun onCreateView(
        inflater: LayoutInflater,
        container: ViewGroup?,
        savedInstanceState: Bundle?
    ): View? {
        // Inicializar binding
        binding = FragmentStorageBinding.inflate(inflater, container, false)
        return binding.root
    }

    override fun onViewCreated(view: View, savedInstanceState: Bundle?) {
        super.onViewCreated(view, savedInstanceState)

        setupListeners()
        observeRetrievedValue()
    }

    /**
     * Configura los listeners de botones del fragment.
     */
    private fun setupListeners() {
        // Botón Guardar: guarda la clave-valor en el almacenamiento seleccionado
        binding.btnSave.setOnClickListener {
            val key = binding.etKey.text?.toString()?.trim()
            val value = binding.etValue.text?.toString()?.trim()

            // Validar que la clave y el valor no estén vacíos
            if (key.isNullOrEmpty() || value.isNullOrEmpty()) {
                showErrorSnackbar("Por favor completa clave y valor")
                return@setOnClickListener
            }

            // Obtener el tipo de almacenamiento seleccionado
            val selectedStorageId = binding.rgStorageType.checkedRadioButtonId

            when (selectedStorageId) {
                binding.rbSharedPrefs.id -> {
                    // Guardar en SharedPreferences
                    viewModel.saveToSharedPrefs(requireContext(), key, value)
                    showSuccessSnackbar("✓ Valor guardado en SharedPreferences")
                }
                binding.rbDataStore.id -> {
                    // Guardar en DataStore
                    viewModel.saveToDataStore(requireContext(), key, value)
                    showSuccessSnackbar("✓ Valor guardado en DataStore")
                }
                binding.rbEncrypted.id -> {
                    // Guardar en EncryptedSharedPreferences
                    viewModel.saveToEncrypted(requireContext(), key, value)
                    showSuccessSnackbar("✓ Valor guardado cifrado")
                }
            }

            // Limpiar campo de valor después de guardar
            binding.etValue.text?.clear()
        }

        // Botón Recuperar: recupera el valor del almacenamiento seleccionado
        binding.btnRetrieve.setOnClickListener {
            val key = binding.etKey.text?.toString()?.trim()

            // Validar que la clave no esté vacía
            if (key.isNullOrEmpty()) {
                showErrorSnackbar("Por favor ingresa una clave")
                return@setOnClickListener
            }

            // Obtener el tipo de almacenamiento seleccionado
            val selectedStorageId = binding.rgStorageType.checkedRadioButtonId

            when (selectedStorageId) {
                binding.rbSharedPrefs.id -> {
                    // Recuperar de SharedPreferences
                    val retrievedValue = viewModel.getFromSharedPrefs(requireContext(), key)
                    handleRetrievedValue(retrievedValue)
                }
                binding.rbDataStore.id -> {
                    // Recuperar de DataStore (asincrónico)
                    viewModel.getFromDataStore(requireContext(), key)
                }
                binding.rbEncrypted.id -> {
                    // Recuperar de EncryptedSharedPreferences
                    val retrievedValue = viewModel.getFromEncrypted(requireContext(), key)
                    handleRetrievedValue(retrievedValue)
                }
            }
        }

        // Cambio en RadioGroup: limpiar resultado y habilitar campo de valor
        binding.rgStorageType.setOnCheckedChangeListener { _, _ ->
            binding.tvResult.text = ""
            binding.etValue.text?.clear()
            binding.etValue.isEnabled = true
        }
    }

    /**
     * Recolecta el StateFlow del ViewModel para valores recuperados.
     * Se usa especialmente para DataStore que retorna un Flow.
     */
    private fun observeRetrievedValue() {
        viewLifecycleOwner.lifecycleScope.launch {
            viewLifecycleOwner.repeatOnLifecycle(Lifecycle.State.STARTED) {
                viewModel.retrievedValue.collect { value ->
                    handleRetrievedValue(value)
                }
            }
        }
    }

    /**
     * Maneja el valor recuperado. Si es null, muestra un mensaje de error.
     * Si existe, lo muestra en el TextView de resultados.
     *
     * @param value El valor recuperado o null
     */
    private fun handleRetrievedValue(value: String?) {
        if (value == null) {
            showErrorSnackbar("Secreto no encontrado")
            binding.tvResult.text = ""
        } else {
            binding.tvResult.text = value
            showSuccessSnackbar("✓ Valor recuperado correctamente")
        }
    }

    /**
     * Muestra un Snackbar con un mensaje de éxito.
     */
    private fun showSuccessSnackbar(message: String) {
        Snackbar.make(binding.root, message, Snackbar.LENGTH_SHORT).show()
    }

    /**
     * Muestra un Snackbar con un mensaje de error.
     */
    private fun showErrorSnackbar(message: String) {
        Snackbar.make(binding.root, message, Snackbar.LENGTH_LONG).show()
    }
}

package com.example.redyseguridad.ui.storage

import android.content.Context
import androidx.datastore.core.DataStore
import androidx.datastore.preferences.core.Preferences
import androidx.datastore.preferences.core.edit
import androidx.datastore.preferences.core.stringPreferencesKey
import androidx.datastore.preferences.preferencesDataStore
import androidx.lifecycle.ViewModel
import androidx.lifecycle.viewModelScope
import androidx.security.crypto.EncryptedSharedPreferences
import androidx.security.crypto.MasterKey
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.launch

// Extensión para acceder al DataStore de forma singleton en toda la app
private val Context.dataStore: DataStore<Preferences> by preferencesDataStore(name = "secure_storage")

/**
 * ViewModel para la pantalla de Almacenamiento Seguro.
 * Gestiona tres tipos de almacenamiento: SharedPreferences, DataStore y EncryptedSharedPreferences.
 * Usa Coroutines para operaciones de I/O en Dispatchers.IO.
 */
class StorageViewModel : ViewModel() {

    // StateFlow que emite el valor recuperado del almacenamiento
    private val _retrievedValue = MutableStateFlow<String?>(null)
    val retrievedValue: StateFlow<String?> = _retrievedValue

    /**
     * SHARED PREFERENCES
     * Guarda un valor en SharedPreferences (almacenamiento no cifrado).
     *
     * @param context Contexto de la aplicación
     * @param key Clave para identificar el valor
     * @param value El valor a guardar
     */
    fun saveToSharedPrefs(context: Context, key: String, value: String) {
        // Obtener la instancia default de SharedPreferences
        val sharedPref = context.getSharedPreferences(
            "com.example.redyseguridad.prefs",
            Context.MODE_PRIVATE
        )
        // Guardar el valor con la clave proporcionada
        sharedPref.edit().putString(key, value).apply()
    }

     /**
      * Recupera un valor de SharedPreferences.
      *
      * @param context Contexto de la aplicación
      * @param key Clave para identificar el valor
      * @return El valor guardado o null si no existe
      */
     fun getFromSharedPrefs(context: Context, key: String): String? {
         val sharedPref = context.getSharedPreferences(
             "com.example.redyseguridad.prefs",
             Context.MODE_PRIVATE
         )
         val value = sharedPref.getString(key, null)
         // También emitir en el StateFlow para mantener consistencia
         _retrievedValue.value = value
         return value
     }

    /**
     * JETPACK DATASTORE
     * Guarda un valor en Jetpack DataStore (almacenamiento con prefs).
     * Usa una coroutine en el viewModelScope que corre en Dispatchers.IO.
     *
     * @param context Contexto de la aplicación
     * @param key Clave para identificar el valor
     * @param value El valor a guardar
     */
    fun saveToDataStore(context: Context, key: String, value: String) {
        // Lanzar coroutine en viewModelScope
        viewModelScope.launch {
            try {
                // Crear una clave de preferencias para almacenar el valor
                val dataStoreKey = stringPreferencesKey(key)

                // Editar el DataStore de forma segura con edit()
                context.dataStore.edit { preferences ->
                    preferences[dataStoreKey] = value
                }
            } catch (e: Exception) {
                // En caso de error, simplemente registrarlo (no se propaga)
                e.printStackTrace()
            }
        }
    }

     /**
      * Recupera un valor de Jetpack DataStore.
      * Lee del Flow y emite el valor en retrievedValue StateFlow una sola vez.
      *
      * @param context Contexto de la aplicación
      * @param key Clave para identificar el valor
      */
     fun getFromDataStore(context: Context, key: String) {
         // Lanzar coroutine en viewModelScope
         viewModelScope.launch {
             try {
                 // Crear una clave de preferencias
                 val dataStoreKey = stringPreferencesKey(key)

                 // Limpiar el valor anterior antes de buscar el nuevo
                 _retrievedValue.value = null

                 // Recopilar el Flow del DataStore, pero solo tomar el primer valor
                 context.dataStore.data.collect { preferences ->
                     val value = preferences[dataStoreKey]
                     // Emitir el valor en el StateFlow
                     _retrievedValue.value = value
                 }
             } catch (e: Exception) {
                 // En caso de error, emitir null
                 _retrievedValue.value = null
                 e.printStackTrace()
             }
         }
     }

    /**
     * ENCRYPTED SHARED PREFERENCES
     * Guarda un valor en EncryptedSharedPreferences (almacenamiento cifrado con AES).
     * Utiliza MasterKey para generar la clave de cifrado.
     *
     * @param context Contexto de la aplicación
     * @param key Clave para identificar el valor
     * @param value El valor a guardar
     */
    fun saveToEncrypted(context: Context, key: String, value: String) {
        try {
            // Crear o recuperar la MasterKey con la clave maestra de la aplicación
            val masterKey = MasterKey.Builder(context)
                .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
                .build()

            // Obtener la instancia de EncryptedSharedPreferences
            val encryptedSharedPref = EncryptedSharedPreferences.create(
                context,
                "com.example.redyseguridad.encrypted_prefs",
                masterKey,
                EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
                EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
            )

            // Guardar el valor cifrado con la clave proporcionada
            encryptedSharedPref.edit().putString(key, value).apply()
        } catch (e: Exception) {
            e.printStackTrace()
        }
    }

     /**
      * Recupera un valor de EncryptedSharedPreferences.
      *
      * @param context Contexto de la aplicación
      * @param key Clave para identificar el valor
      * @return El valor descifrado o null si no existe
      */
     fun getFromEncrypted(context: Context, key: String): String? {
         return try {
             // Crear o recuperar la MasterKey
             val masterKey = MasterKey.Builder(context)
                 .setKeyScheme(MasterKey.KeyScheme.AES256_GCM)
                 .build()

             // Obtener la instancia de EncryptedSharedPreferences
             val encryptedSharedPref = EncryptedSharedPreferences.create(
                 context,
                 "com.example.redyseguridad.encrypted_prefs",
                 masterKey,
                 EncryptedSharedPreferences.PrefKeyEncryptionScheme.AES256_SIV,
                 EncryptedSharedPreferences.PrefValueEncryptionScheme.AES256_GCM
             )

             // Recuperar e desencriptar el valor
             val value = encryptedSharedPref.getString(key, null)
             // También emitir en el StateFlow para mantener consistencia
             _retrievedValue.value = value
             value
         } catch (e: Exception) {
             _retrievedValue.value = null
             null
         }
     }

    /**
     * Limpia el StateFlow de valores recuperados.
     */
    fun clearRetrievedValue() {
        _retrievedValue.value = null
    }
}

